import keras

class GatedDenseBlock(keras.Layer):
    def __init__(self, units, **kwargs):
        super().__init__(**kwargs)
        self.dense = keras.layers.Dense(units)
        self.gate  = keras.layers.Dense(units, activation="sigmoid")
        self.norm  = keras.layers.LayerNormalization()

    def build(self, input_shape):
        # Sublayer weights are built on first call automatically;
        # declare any *direct* weights here if needed.
        super().build(input_shape)

    def call(self, x, training=False):
        h = keras.activations.gelu(self.dense(x))
        g = self.gate(x)
        return self.norm(h * g)

# Usage
block = GatedDenseBlock(128)
model = keras.Sequential([keras.layers.Input((64,)), block, keras.layers.Dense(10)])
model.summary()

import tensorflow as tf

class CustomModel(tf.keras.Model):
    def train_step(self, data):
        x, y = data

        with tf.GradientTape() as tape:
            y_pred = self(x, training=True)          # forward pass
            loss = self.compiled_loss(y, y_pred)     # loss computation

        gradients = tape.gradient(loss, self.trainable_variables)  # backprop
        self.optimizer.apply_gradients(             # optimizer step
            zip(gradients, self.trainable_variables)
        )
        self.compiled_metrics.update_state(y, y_pred)
        return {m.name: m.result() for m in self.metrics}

import keras
import tensorflow as tf

class FocalLoss(keras.losses.Loss):
    def __init__(self, gamma=2.0, **kwargs):
        super().__init__(**kwargs)
        self.gamma = gamma

    def call(self, y_true, y_pred):
        bce = keras.losses.binary_crossentropy(
            y_true, y_pred, from_logits=False
        )
        p_t = y_true * y_pred + (1 - y_true) * (1 - y_pred)
        return bce * tf.pow(1.0 - p_t, self.gamma)

model.compile(
    optimizer="adam",
    loss=FocalLoss(gamma=2.0),
)
